// ======================================================================
// Tokenizer runtime
// ======================================================================

/// One token from the input stream.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Token {
    /// The rule id that matched.  Compare to JSON_RULE_*
    /// constants to identify which rule fired.
    pub rule_id: u16,
    /// Byte offset of the matched text in the input.
    pub start: usize,
    /// Length of the matched text in bytes.
    pub len: usize,
    /// 1-based line number of the first byte.
    pub line: u32,
    /// 1-based column number of the first byte.
    pub column: u32,
}

/// Errors returned by the lexer.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum LexError {
    /// No matching rule at the given offset.  byte is the
    /// offending byte; offset is its index.
    NoMatch { offset: usize, byte: u8 },
    /// Requested state name doesn't exist.
    UnknownState,
}

/// Lexer state identifier.  Use the START_STATE_* constants.
pub type StateId = u16;

/// Per-named-state DFA dispatch.
/// Calls into the per-state-group step_* function
/// generated by emit_state_dfa (a giant Rust
/// match expression that LLVM lowers to a jump table).
#[inline(always)]
fn dfa_step_for_state(s: StateId, state: u16, b: u8) -> i16 {
    match s {
        0 => step_INITIAL(state, b),
        _ => -1,
    }
}

/// Fast-path dispatcher: state group + DFA state
/// -> advanced byte position after SIMD scan.
#[inline(always)]
fn fast_path_for_state_g<S: Scanner>(s: StateId, state: u16, bytes: &[u8], p: usize) -> usize {
    match s {
        0 => fast_path_INITIAL_g::<S>(state, bytes, p),
        _ => p,
    }
}

#[inline(always)]
fn dfa_accept_for_state(s: StateId) -> &'static [i16] {
    match s {
        0 => JSON_INITIAL_ACCEPT,
        _ => &[],
    }
}

#[inline(always)]
fn dfa_start_for_state(s: StateId) -> u16 {
    match s {
        0 => JSON_INITIAL_START,
        _ => 0,
    }
}

pub const STATE_INITIAL: StateId = 0;

/// Lexer.  Stateless aside from the active state name; the
/// caller drives tokenize() with a complete input string and
/// receives a Vec<Token>.
pub struct Lexer {
    state: StateId,
}

impl Lexer {
    /// Construct a lexer in the INITIAL state (state 0).
    pub fn new() -> Self { Self { state: 0 } }

    /// Set the active state.  Use STATE_* constants.
    pub fn set_state(&mut self, s: StateId) { self.state = s; }

    /// Get the active state.
    pub fn state(&self) -> StateId { self.state }

    /// Tokenise an input string.  Returns the full token stream
    /// when the input is fully consumed; returns Err with the
    /// offending offset on no-match.
    ///
    /// Performance: O(input.len()) with a small per-byte cost
    /// (one DFA transition + bookkeeping).  No allocations
    /// per token beyond the result Vec.
    pub fn tokenize(&mut self, input: &str) -> Result<Vec<Token>, LexError> {
        let bytes = input.as_bytes();
        #[cfg(target_arch = "x86_64")]
        {
            if std::arch::is_x86_feature_detected!("avx2") {
                return unsafe { self.tokenize_avx2(bytes) };
            }
        }
        #[cfg(target_arch = "aarch64")]
        {
            return unsafe { self.tokenize_neon(bytes) };
        }
        #[allow(unreachable_code)]
        self.tokenize_scalar(bytes)
    }

    #[cfg(target_arch = "x86_64")]
    #[target_feature(enable = "avx2,bmi2")]
    unsafe fn tokenize_avx2(&mut self, bytes: &[u8]) -> Result<Vec<Token>, LexError> {
        self.tokenize_impl::<AvxScanner>(bytes)
    }

    #[cfg(target_arch = "aarch64")]
    unsafe fn tokenize_neon(&mut self, bytes: &[u8]) -> Result<Vec<Token>, LexError> {
        self.tokenize_impl::<NeonScanner>(bytes)
    }

    fn tokenize_scalar(&mut self, bytes: &[u8]) -> Result<Vec<Token>, LexError> {
        self.tokenize_impl::<ScalarScanner>(bytes)
    }

    #[inline(always)]
    fn tokenize_impl<S: Scanner>(&mut self, bytes: &[u8]) -> Result<Vec<Token>, LexError> {
        let mut out = Vec::new();
        let mut pos: usize = 0;
        let mut line: u32 = 1;
        let mut column: u32 = 1;
        while pos < bytes.len() {
            let accept = dfa_accept_for_state(self.state);
            let mut state: u16 = dfa_start_for_state(self.state);
            let mut last_accept: i16 = -1;
            let mut last_accept_pos: usize = pos;
            let mut p = pos;
            unsafe {
                while p < bytes.len() {
                    let new_p = fast_path_for_state_g::<S>(self.state, state, bytes, p);
                    if new_p > p {
                        let accv = *accept.get_unchecked(state as usize);
                        if accv >= 0 {
                            last_accept = accv;
                            last_accept_pos = new_p;
                        }
                        p = new_p;
                        if p >= bytes.len() { break; }
                    }
                    let b = *bytes.get_unchecked(p);
                    let next = dfa_step_for_state(self.state, state, b);
                    if next < 0 { break; }
                    state = next as u16;
                    let accv = *accept.get_unchecked(state as usize);
                    if accv >= 0 {
                        last_accept = accv;
                        last_accept_pos = p + 1;
                    }
                    p += 1;
                }
            }
            if last_accept < 0 {
                return Err(LexError::NoMatch { offset: pos, byte: bytes[pos] });
            }
            let tok_start = pos;
            let tok_len = last_accept_pos - pos;
            let tok_line = line;
            let tok_col = column;
            for &b in &bytes[pos..last_accept_pos] {
                if b == b'\n' { line += 1; column = 1; }
                else if b != b'\r' { column += 1; }
            }
            out.push(Token {
                rule_id: last_accept as u16,
                start: tok_start,
                len: tok_len,
                line: tok_line,
                column: tok_col,
            });
            pos = last_accept_pos;
        }
        Ok(out)
    }
}

impl Default for Lexer {
    fn default() -> Self { Self::new() }
}

/// Streaming token iterator (does NOT allocate a Vec).
/// Created via Lexer::iter().  Yields
/// Result<Token, LexError> per next() call.  Uses the
/// scalar scan path; for SIMD-accelerated bulk parsing
/// of large inputs, prefer tokenize() -> Vec<Token>.
pub struct TokenIter<'a, 'b> {
    lexer: &'a mut Lexer,
    bytes: &'b [u8],
    pos: usize,
    line: u32,
    column: u32,
}

impl<'a, 'b> Iterator for TokenIter<'a, 'b> {
    type Item = Result<Token, LexError>;
    fn next(&mut self) -> Option<Self::Item> {
        if self.pos >= self.bytes.len() { return None; }
        let accept = dfa_accept_for_state(self.lexer.state);
        let mut state: u16 = dfa_start_for_state(self.lexer.state);
        let mut last_accept: i16 = -1;
        let mut last_accept_pos: usize = self.pos;
        let mut p = self.pos;
        unsafe {
            while p < self.bytes.len() {
                let b = *self.bytes.get_unchecked(p);
                let next = dfa_step_for_state(self.lexer.state, state, b);
                if next < 0 { break; }
                state = next as u16;
                let accv = *accept.get_unchecked(state as usize);
                if accv >= 0 {
                    last_accept = accv;
                    last_accept_pos = p + 1;
                }
                p += 1;
            }
        }
        if last_accept < 0 {
            let off = self.pos;
            let byte = self.bytes[self.pos];
            self.pos = self.bytes.len();
            return Some(Err(LexError::NoMatch { offset: off, byte }));
        }
        let tok = Token {
            rule_id: last_accept as u16,
            start: self.pos,
            len: last_accept_pos - self.pos,
            line: self.line,
            column: self.column,
        };
        for &b in &self.bytes[self.pos..last_accept_pos] {
            if b == b'\n' { self.line += 1; self.column = 1; }
            else if b != b'\r' { self.column += 1; }
        }
        self.pos = last_accept_pos;
        Some(Ok(tok))
    }
}

impl Lexer {
    /// Stream tokens one at a time without allocating a Vec.
    /// Useful when input is large or the consumer can process
    /// tokens incrementally.  Uses the scalar scan path.
    pub fn iter<'a, 'b>(&'a mut self, input: &'b str) -> TokenIter<'a, 'b> {
        TokenIter {
            lexer: self,
            bytes: input.as_bytes(),
            pos: 0,
            line: 1,
            column: 1,
        }
    }
}
